import React, { useState } from "react";
import axios from "axios";

function App() {

const [input,setInput] = useState("");
const [messages,setMessages] = useState([]);

const userId = "1";

const sendMessage = async () => {

if(!input.trim()) return;

const userMessage = {
role:"user",
message:input
};

setMessages(prev => [...prev,userMessage]);

try{

const res = await axios.post(
"http://localhost:5001/api/chat",
{
message:input,
userId:userId
}
);

const aiMessage = {
role:"assistant",
message:res.data.reply
};

setMessages(prev => [...prev,aiMessage]);

}catch(err){

setMessages(prev => [...prev,{
role:"assistant",
message:"AI Error"
}]);

}

setInput("");

};

return(

<div style={styles.container}>

<h1 style={styles.title}>🤖 AI Chatbot</h1>

<div style={styles.chatBox}>

{messages.map((msg,index)=>(
<div
key={index}
style={msg.role==="user"?styles.user:styles.ai}
>
{msg.message}
</div>
))}

</div>

<div style={styles.inputArea}>

<input
style={styles.input}
value={input}
onChange={(e)=>setInput(e.target.value)}
placeholder="Ask something..."
/>

<button
style={styles.button}
onClick={sendMessage}
>
Send
</button>

</div>

</div>

);

}

const styles = {

container:{
background:"#0f172a",
height:"100vh",
padding:"20px",
color:"white",
fontFamily:"Arial"
},

title:{
textAlign:"center"
},

chatBox:{
background:"#1e293b",
height:"70vh",
overflowY:"auto",
padding:"10px",
borderRadius:"10px",
marginTop:"20px"
},

user:{
background:"#2563eb",
padding:"10px",
margin:"10px",
borderRadius:"8px",
textAlign:"right"
},

ai:{
background:"#334155",
padding:"10px",
margin:"10px",
borderRadius:"8px"
},

inputArea:{
marginTop:"15px",
display:"flex",
gap:"10px"
},

input:{
flex:1,
padding:"10px",
borderRadius:"6px",
border:"none"
},

button:{
padding:"10px 15px",
background:"#22c55e",
border:"none",
color:"white",
borderRadius:"6px",
cursor:"pointer"
}

};

export default App;
